    def drag(self, x, y, speed=40, shake=True):
        """拖拽当前元素到相对位置
        :param x: x变化值
        :param y: y变化值
        :param speed: 拖动的速度，传入0即瞬间到达
        :param shake: 是否随机抖动
        :return: None
