        return self.driver.current_window_handle

    @property
    def active_ele(self):
        """返回当前焦点所在元素"""
        return DriverElement(self.driver.switch_to.active_element, self)

    @property
    def scroll(self):
        """用于滚动滚动条的对象"""
        if self._scroll is None:
