            self.driver.set_script_timeout(script)

    def wait_ele(self, loc_or_ele, timeout=None):
        """等待元素从dom删除、显示、隐藏
        :param loc_or_ele: 可以是元素、查询字符串、loc元组
        :param timeout: 等待超时时间
