    @property
    def wait_object(self):
        """返回WebDriverWait对象，重用避免每次新建对象"""
        if self._wait_object is None:
            self._wait_object = WebDriverWait(self.driver, timeout=self.timeout)

        return self._wait_object

    @property
    def timeouts(self):
        """返回三种超时时间，selenium4以上版本可用"""
