    def run_async_script(self, script, *args):
        """以异步方式执行js代码
        :param script: js文本
        :param args: 传入的参数
        :return: js执行结果
        """
        return self.driver.execute_async_script(script, *args)

    def run_cdp(self, cmd, **cmd_args):
